import React, { useState } from 'react';

const ContactPage = () => {
  // Grouping our form fields into one state object
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });

  // Grouping our error messages into another state object
  const [errors, setErrors] = useState({
    name: '',
    email: '',
    message: ''
  });

  // This function updates the state whenever a user types in an input
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ 
      ...formData, 
      [name]: value 
    });
    // Clear the specific error for this field as the user starts typing again
    setErrors({ 
      ...errors, 
      [name]: '' 
    });
  };

  // This handles the validation when the form is submitted
  const handleSubmit = (e) => {
    e.preventDefault(); // Prevents the page from reloading
    
    let isValid = true;
    let newErrors = { name: '', email: '', message: '' };

    // Validation Rules
    if (formData.name.trim() === "") {
      newErrors.name = "Name is required";
      isValid = false;
    }

    if (!/^[^@]+@[^@]+\.[^@]+$/.test(formData.email)) {
      newErrors.email = "Valid email is required";
      isValid = false;
    }

    if (formData.message.trim().length < 10) {
      newErrors.message = "Message must be at least 10 characters";
      isValid = false;
    }

    setErrors(newErrors);

    if (isValid) {
      alert("Message Sent (Simulated)!");
      // Optional: Clear the form after a successful send
      setFormData({ name: '', email: '', message: '' });
    }
  };

  return (
    <main>
      <section>
        <h2 style={{ textAlign: 'center', marginBottom: '20px' }}>Contact Me</h2>
        
        <div className="form-container">
          
          <div className="map-container">
            {/* Added a 'title' attribute to the iframe to fix a common React accessibility warning */}
            <iframe 
              src="https://maps.google.com/maps?q=Agoo%2C%20La%20Union%2C%20Philippines&t=&z=13&ie=UTF8&iwloc=&output=embed" 
              title="Location Map"
              allowFullScreen>
            </iframe>
          </div>

          <form onSubmit={handleSubmit}>
            <label htmlFor="cName">Name:</label>
            <input 
              type="text" 
              id="cName" 
              name="name" // The name attribute must match the key in formData state
              placeholder="Your Name"
              value={formData.name}
              onChange={handleChange}
            />
            {/* Conditionally render the error span only if there is an error */}
            {errors.name && <span className="error">{errors.name}</span>}

            <label htmlFor="cEmail">Email:</label>
            <input 
              type="text" 
              id="cEmail" 
              name="email"
              placeholder="your@email.com"
              value={formData.email}
              onChange={handleChange}
            />
            {errors.email && <span className="error">{errors.email}</span>}

            <label htmlFor="cMessage">Message:</label>
            <textarea 
              id="cMessage" 
              name="message"
              rows="5" 
              placeholder="Write something..."
              value={formData.message}
              onChange={handleChange}
            ></textarea>
            {errors.message && <span className="error">{errors.message}</span>}

            <button type="submit" className="quiz-btn">Send Message</button>
          </form>
        </div>
      </section>
    </main>
  );
};

export default ContactPage;
